# Language-aware code splitting: splits on function/class boundaries
# Prevents splitting a function body across two chunks.

from langchain_text_splitters import Language, RecursiveCharacterTextSplitter

python_splitter = RecursiveCharacterTextSplitter.from_language(
    language=Language.PYTHON,
    chunk_size=512,
    chunk_overlap=32,
)

code = """
def calculate_discount(price: float, pct: float) -> float:
    """Apply a percentage discount to a price."""
    if not 0 <= pct <= 100:
        raise ValueError(f"Discount {pct}% is out of range")
    return price * (1 - pct / 100)


class ShoppingCart:
    def __init__(self):
        self.items: list[dict] = []

    def add(self, name: str, price: float, qty: int = 1):
        self.items.append({"name": name, "price": price, "qty": qty})

    def total(self) -> float:
        return sum(i["price"] * i["qty"] for i in self.items)

    def apply_discount(self, pct: float) -> float:
        return calculate_discount(self.total(), pct)
"""

chunks = python_splitter.split_text(code)
print(f"Code chunks: {len(chunks)}")
for i, c in enumerate(chunks):
    print(f"  [{i}] {len(c)} chars: {c[:60]!r}")
# Python splitter splits on def/class boundaries — each function/class is its own chunk.
# Also supports: Language.JS, Language.TS, Language.GO, Language.RUST, Language.JAVA
